function formatTradeTime(ts: string): string {
  const d = new Date(ts)
  return d.toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false })
}

function scheduleTickAnimatedField(field: string): void {
  tickAnimatedFields.value = { ...tickAnimatedFields.value, [field]: true }

  const existingTimer = tickAnimatedFieldTimers.get(field)
  if (existingTimer) clearTimeout(existingTimer)

  tickAnimatedFieldTimers.set(field, setTimeout(() => {
    const nextFields = { ...tickAnimatedFields.value }
    delete nextFields[field]
    tickAnimatedFields.value = nextFields
    tickAnimatedFieldTimers.delete(field)
  }, TICK_FEEDBACK_DURATION_MS))
}

function tickAnimatedFieldClass(field: string): string {
  return tickAnimatedFields.value[field] ? 'tick-value-flash' : ''
}

function scheduleRecentTradeAnimation(trade: RecentTrade): void {
  const tradeKey = recentTradeIdentity(trade)
  const animationTone = trade.side === 'sell' ? 'sell' : 'buy'
  recentTradeAnimations.value = {
    ...recentTradeAnimations.value,
    [tradeKey]: animationTone,
  }

  const existingTimer = recentTradeAnimationTimers.get(tradeKey)
  if (existingTimer) clearTimeout(existingTimer)

  recentTradeAnimationTimers.set(tradeKey, setTimeout(() => {
    const nextAnimations = { ...recentTradeAnimations.value }
    delete nextAnimations[tradeKey]
    recentTradeAnimations.value = nextAnimations
    recentTradeAnimationTimers.delete(tradeKey)
  }, TICK_FEEDBACK_DURATION_MS))
}

function recentTradeAnimationClass(trade: RecentTrade): string {
  const animationTone = recentTradeAnimations.value[recentTradeIdentity(trade)]
  if (animationTone === 'buy') return 'trade-tick-enter-buy'
  if (animationTone === 'sell') return 'trade-tick-enter-sell'
  return ''
}

function compactQtyText(n: NumericLike): string {
  return formatCompactNumber(n)
}

function toApproxPrice(value: NumericLike, fallback = 0): number {
  return exactToApproxNumber(value) ?? fallback
}

function percentText(value: number): string {
  return formatSignedPercent(value, { digits: 2 })
}

function formatSpread(value: number): string {
  return formatSharedPercent(value, { digits: 2 })
}

function getDisplayedSpreadPct(data: Pick<MarketData, 'bid' | 'ask' | 'spread_pct'>): number {
  const bid = toApproxPrice(data.bid)
  const ask = toApproxPrice(data.ask)
  if (!Number.isFinite(bid) || !Number.isFinite(ask) || bid <= 0 || ask <= 0 || ask < bid) {
    return data.spread_pct
  }

  const midpoint = (ask + bid) / 2
  if (midpoint <= 0) {
    return data.spread_pct
  }

  return (ask - bid) / midpoint
}

function formatProfitPrice(value: NumericLike): string {
  return formatSignedCurrency(value)
}

function formatNetFlow(value: NumericLike): string {
  const amount = currencyText(value).replace(/^\$/, '')
  return quantityNumber(value) >= 0 ? `+$${amount}` : `$-${amount}`
}

function formatExpiry(hoursUntilExpiry: number): string {
  if (hoursUntilExpiry <= 0) return '已过期'
  const hours = Math.floor(hoursUntilExpiry)
  const minutes = Math.round((hoursUntilExpiry - hours) * 60)
  return `${hours}小时${minutes}分钟`
}

function formatSettlement(hoursUntilSettlement: number): string {
  if (hoursUntilSettlement <= 0) return '可售'
  const hours = Math.floor(hoursUntilSettlement)
  const minutes = Math.round((hoursUntilSettlement - hours) * 60)
  return `${hours}h${minutes}m后可售`
}

function slippagePreviewText(side: 'buy' | 'sell'): string {
  if (!market.value) return ''
  const slippage = parseFloat(side === 'buy' ? (buySlippage.value || '0') : (sellSlippage.value || '0'))
  const base = toApproxPrice(side === 'buy' ? market.value.ask : market.value.bid)
  const adjusted = side === 'buy'
    ? base * (1 + slippage / 100)
    : base * (1 - slippage / 100)
  return priceText(adjusted)
}

function transactionMidDeltaClass(tx: TurnipTransaction): string {
  if (tx.mid_price === null) return ''
  const unitPrice = toApproxPrice(tx.unit_price)
  const midPrice = toApproxPrice(tx.mid_price)
  if (unitPrice <= 0 || midPrice <= 0) return ''
  return (unitPrice - midPrice) / midPrice > 0 ? 'text-danger' : 'text-success'
}

function transactionMidDeltaText(tx: TurnipTransaction): string {
  if (tx.mid_price === null) return ''
  const unitPrice = toApproxPrice(tx.unit_price)
  const midPrice = toApproxPrice(tx.mid_price)
  if (unitPrice <= 0 || midPrice <= 0) return ''
  return `${(Math.abs((unitPrice - midPrice) / midPrice) * 100).toFixed(2)}%`
}

function profitColor(value: NumericLike): string {
  const approx = quantityNumber(value)
  if (approx > 0) return 'var(--color-success)'
  if (approx < 0) return 'var(--color-danger)'
  return 'var(--color-text-primary)'
}

function formatDuration(seconds: number): string {
  if (seconds <= 0) return '已成熟'
  const h = Math.floor(seconds / 3600)
  const m = Math.floor((seconds % 3600) / 60)
  if (h > 0) return `${h}h${m}m`
  return `${m}m`
}

function formatDateTime(iso: string): string {
  const d = new Date(iso)
  const MM = (d.getMonth() + 1).toString().padStart(2, '0')
  const DD = d.getDate().toString().padStart(2, '0')
  const hh = d.getHours().toString().padStart(2, '0')
  const mm = d.getMinutes().toString().padStart(2, '0')
  const ss = d.getSeconds().toString().padStart(2, '0')
  return `${MM}-${DD} ${hh}:${mm}:${ss}`
}

function getTxTypeLabel(txType: string): string {
  const labels: Record<string, string> = {
    harvest: '收获',
    buy: '买入',
    sell: '卖出',
    expire: '过期',
    gift_in: '收礼',
    gift_out: '送礼',
    consume: '消耗',
  }
  return labels[txType] || txType
}

function parseErrorMessage(error: unknown, fallback: string): string {
  const maybeAxios = error as { response?: { data?: { detail?: string } }; message?: string }
  return maybeAxios.response?.data?.detail || maybeAxios.message || fallback
}

function toNumber(value: unknown, fallback = 0): number {
  return coerceFiniteNumber(value) ?? fallback
}

function toNullableNumber(value: unknown): number | null {
  return coerceFiniteNumber(value)
}

function normalizeRecentTrade(trade: RecentTrade): RecentTrade {
  return trade
}

function recentTradeIdentity(trade: RecentTrade): string {
  if (trade.id != null) {
    return `trade:${trade.id}`
  }
  return [trade.ts, trade.side, trade.qty, trade.price].join('|')
}

function sortRecentTradesNewestFirst(trades: RecentTrade[]): RecentTrade[] {
  return [...trades].sort((a, b) => new Date(b.ts).getTime() - new Date(a.ts).getTime())
}

function normalizeMarketData(data: MarketData): MarketData {
  return {
    ...data,
    current_price: toNumber(data.current_price),
    bid: toNumber(data.bid),
    ask: toNumber(data.ask),
    spread_pct: toNumber(data.spread_pct),
    treasury_cash_balance: toNumber(data.treasury_cash_balance),
    avg_buy_price: toNumber(data.avg_buy_price),
    total_value: toNumber(data.total_value),
    volume: toNumber(data.volume),
    buy_volume: toNumber(data.buy_volume),
    sell_volume: toNumber(data.sell_volume),
    recent_trades: sortRecentTradesNewestFirst(data.recent_trades.map(normalizeRecentTrade)),
  }
}

function normalizePricePoint(point: PricePoint): PricePoint {
  return {
    ...point,
    open: toNullableNumber(point.open),
    high: toNullableNumber(point.high),
    low: toNullableNumber(point.low),
    close: toNumber(point.close),
  }
}

function normalizeDepthData(data: DepthData): DepthData {
  return {
    ...data,
    mid_price: toNumber(data.mid_price),
    bid: toNumber(data.bid),
    ask: toNumber(data.ask),
    spread_pct: toNumber(data.spread_pct),
    depth: toNumber(data.depth),
    bids: data.bids.map((level) => ({ ...level, price: toNumber(level.price) })),
    asks: data.asks.map((level) => ({ ...level, price: toNumber(level.price) })),
  }
}

function normalizeDepthDataFromTick(tick: {
  mid_price: string
  bid: string | null
  ask: string | null
  spread_pct?: number
  depth?: NumericLike
  bids?: DepthLevel[]
  asks?: DepthLevel[]
}): DepthData | null {
  if (tick.bid == null || tick.ask == null || tick.depth == null || !tick.bids || !tick.asks) {
    return null
  }

  const midPrice = coerceFiniteNumber(tick.mid_price)
  const bid = coerceFiniteNumber(tick.bid)
  const ask = coerceFiniteNumber(tick.ask)

  if (midPrice === null || bid === null || ask === null) {
    return null
  }

  return normalizeDepthData({
    mid_price: midPrice,
    bid,
    ask,
    spread_pct: typeof tick.spread_pct === 'number'
      ? tick.spread_pct
      : getDisplayedSpreadPct({ bid, ask, spread_pct: 0 }),
    depth: toNumber(tick.depth),
    bids: tick.bids,
    asks: tick.asks,
  })
}

