// --- Net flow ---

const netFlow = computed(() => {
  if (!market.value) return 0
  return toApproxPrice(market.value.buy_volume) - toApproxPrice(market.value.sell_volume)
})

const displayedSpreadPct = computed(() => {
  if (!market.value) return 0
  return getDisplayedSpreadPct(market.value)
})

// --- Portfolio helpers ---

const portfolioEmpty = computed(() => {
  return inventory.value !== null && quantityNumber(inventory.value.total_quantity) === 0
})

function batchCurrentValue(batch: Batch): number {
  if (!inventory.value) return 0
  return quantityNumber(batch.quantity) * toApproxPrice(inventory.value.current_price)
}

function batchPnL(batch: Batch): number {
  return batchCurrentValue(batch) - toApproxPrice(batch.total_cost)
}

// --- Farm helpers ---

const matureSeedCount = computed(() => {
  if (!farm.value) return 0
  return farm.value.seeds.filter((seed) => seed.status === 'mature').length
})

const growingSeedCount = computed(() => {
  if (!farm.value) return 0
  return farm.value.seeds.filter((seed) => seed.status === 'growing').length
})

const farmAvailable = computed(() => {
  if (!farm.value) return 0
  return Math.max(0, farm.value.farm_total - farm.value.farm_used)
})

function seedMaturityPercent(seed: SeedBatch): number {
  if (seed.status === 'mature') return 100
  if (seed.original_time_remaining_seconds === null) return 100
  const planted = new Date(seed.planted_at).getTime()
  const matures = new Date(seed.matures_at).getTime()
  const total = matures - planted
  if (total <= 0) return 100
  const elapsed = total - seed.original_time_remaining_seconds * 1000
  return Math.min(100, Math.max(0, (elapsed / total) * 100))
}

function seedDecayPercent(seed: SeedBatch): number {
  if (seed.status !== 'mature') return 0
  // decay_rate is fraction of quantity lost; show as percentage
  return Math.min(100, seed.decay_rate * 100)
}

function harvesterTimeRemaining(farm: FarmData): string {
  if (!farm.harvester_expires_at) return ''
  const remaining = new Date(farm.harvester_expires_at).getTime() - Date.now()
  if (remaining <= 0) return '已过期'
  const h = Math.floor(remaining / 3600000)
  const m = Math.floor((remaining % 3600000) / 60000)
  return `${h}h${m}m`
}

function harvesterPrice(): number {
  return farm.value?.auto_harvester_price ?? 10000
}

function harvesterDurationHours(): number {
  return farm.value?.auto_harvester_duration_hours ?? 24
}

function isDepthView(mode: 'line' | 'candlestick' | 'depth' | 'orderbook' = viewMode.value): boolean {
  return mode === 'depth' || mode === 'orderbook'
}

function isDepthChartMode(mode: 'line' | 'candlestick' | 'depth' | 'orderbook' = viewMode.value): boolean {
  return mode === 'depth'
}

const LIGHTWEIGHT_CHART_SAFE_ABS_VALUE = 90_000_000_000_000
const LIGHTWEIGHT_CHART_MIN_MOVE = 0.00000001
const DEPTH_CHART_MIN_TIME_STEP = 0.000001

function getLightweightChartScaleFactor(maxAbs: number): number {
  if (!Number.isFinite(maxAbs) || maxAbs <= LIGHTWEIGHT_CHART_SAFE_ABS_VALUE) {
    return 1
  }

  return 10 ** Math.ceil(Math.log10(maxAbs / LIGHTWEIGHT_CHART_SAFE_ABS_VALUE))
}

function scaleChartValue(value: number, scaleFactor: number): number {
  return value / scaleFactor
}

function unscaleChartValue(value: number, scaleFactor: number): number {
  return value * scaleFactor
}

const priceChartValueScaleFactor = computed(() => {
  let maxAbs = 0
  for (const point of filteredPrices.value) {
    maxAbs = Math.max(
      maxAbs,
      Math.abs(point.open ?? point.close),
      Math.abs(point.high ?? point.close),
      Math.abs(point.low ?? point.close),
      Math.abs(point.close),
    )
  }
  return getLightweightChartScaleFactor(maxAbs)
})

const volumeChartValueScaleFactor = computed(() => {
  let maxAbs = 0
  for (const point of filteredPrices.value) {
    maxAbs = Math.max(maxAbs, Math.abs(quantityNumber(point.volume)))
  }
  return getLightweightChartScaleFactor(maxAbs)
})

function scalePriceChartValue(value: number): number {
  return scaleChartValue(value, priceChartValueScaleFactor.value)
}

function unscalePriceChartValue(value: number): number {
  return unscaleChartValue(value, priceChartValueScaleFactor.value)
}

function scaleVolumeChartValue(value: number): number {
  return scaleChartValue(value, volumeChartValueScaleFactor.value)
}

function unscaleVolumeChartValue(value: number): number {
  return unscaleChartValue(value, volumeChartValueScaleFactor.value)
}

const depthPriceChartScaleFactor = computed(() => {
  if (!depthData.value) return 1

  let maxAbs = Math.max(
    Math.abs(toApproxPrice(depthData.value.mid_price)),
    Math.abs(toApproxPrice(depthData.value.bid)),
    Math.abs(toApproxPrice(depthData.value.ask)),
  )

  for (const level of depthData.value.bids) {
    maxAbs = Math.max(maxAbs, Math.abs(toApproxPrice(level.price)))
  }
  for (const level of depthData.value.asks) {
    maxAbs = Math.max(maxAbs, Math.abs(toApproxPrice(level.price)))
  }

  return getLightweightChartScaleFactor(maxAbs)
})

function scaleDepthPriceChartValue(value: number): number {
  return scaleChartValue(value, depthPriceChartScaleFactor.value)
}

function unscaleDepthPriceChartValue(value: number): number {
  return unscaleChartValue(value, depthPriceChartScaleFactor.value)
}

function unscaleDepthQuantityChartValue(value: number): number {
  const scaledQuantity = unscaleChartValue(value, depthQuantityChartScaleFactor.value)
  return depthLogScale.value ? Math.expm1(scaledQuantity) : scaledQuantity
}

// --- Chart ---

function getIntervalMinutes(): number {
  const r = timeRange.value
  if (r === 1) return 1
  if (r <= 6) return 5
  return 15
}

const filteredPrices = computed(() => {
  return prices.value
})

const latestCandle = computed(() => {
  const pts = filteredPrices.value
  return pts.length > 0 ? pts[pts.length - 1] : null
})

const rangeVolume = computed(() => {
  return filteredPrices.value.reduce((sum, p) => sum + quantityNumber(p.volume), 0)
})

const stats24h = computed(() => {
  const cutoff = Date.now() - 24 * 60 * 60 * 1000
  const pts = prices.value.filter((p) => new Date(p.created_at).getTime() >= cutoff)
  if (pts.length === 0) return null
  const open = pts[0].open ?? pts[0].close
  const close = pts[pts.length - 1].close
  const high = Math.max(...pts.map((p) => p.high ?? p.close))
  const low = Math.min(...pts.map((p) => p.low ?? p.close))
  const change = close - open
  const changePct = open > 0 ? change / open : 0
  return { open, high, close, low, change, changePct }
})

function toTime(ts: string): UTCTimestamp {
  const d = new Date(ts)
  // Shift by local TZ offset so lightweight-charts (which always renders UTC) shows local time
  return Math.floor((d.getTime() - d.getTimezoneOffset() * 60_000) / 1000) as UTCTimestamp
}

function onPriceChartInteractionStart() {
  priceChartInteracting = true
}

function onPriceChartInteractionEnd() {
  if (!priceChartInteracting) return
  priceChartInteracting = false

  if (deferredPriceChartFit === null || isDepthView()) return

  const fit = deferredPriceChartFit
  deferredPriceChartFit = null
  nextTick(() => {
    syncPriceChartData(fit)
  })
}

function destroyPriceChart() {
  if (resizeObserver) {
    resizeObserver.disconnect()
    resizeObserver = null
  }
  if (priceChart) {
    priceChart.remove()
    priceChart = null
  }
  priceSeries = null
  volumeSeries = null
  priceChartInteracting = false
  deferredPriceChartFit = null
}

function destroyDepthChart() {
  if (depthResizeObserver) {
    depthResizeObserver.disconnect()
    depthResizeObserver = null
  }
  if (depthChart) {
    depthChart.remove()
    depthChart = null
  }
  depthBidSeriesList = []
  depthAskSeriesList = []
  hoveredDepthPoint.value = null
}

function setupPriceChart() {
  const container = priceChartContainer.value
  if (!container) return

  destroyPriceChart()

  priceChart = createChart(container, {
    height: container.clientHeight,
    width: container.clientWidth,
    layout: {
      background: { type: ColorType.Solid, color: 'transparent' },
      textColor: '#8e8e9d',
    },
    grid: {
      vertLines: { color: 'rgba(50,50,62,0.5)' },
      horzLines: { color: 'rgba(50,50,62,0.5)' },
    },
    crosshair: {
      mode: CrosshairMode.Normal,
    },
    timeScale: {
      borderColor: '#32323e',
      timeVisible: true,
      secondsVisible: false,
    },
    rightPriceScale: {
      borderColor: '#32323e',
      scaleMargins: { top: 0.1, bottom: 0.25 },
    },
  })

  volumeSeries = priceChart.addSeries(HistogramSeries, {
    priceScaleId: 'volume',
    color: '#6b6b82',
    priceFormat: {
      type: 'custom',
      minMove: LIGHTWEIGHT_CHART_MIN_MOVE,
      formatter: (value: number) => quantityText(unscaleVolumeChartValue(value)),
      tickmarksFormatter: (values: readonly number[]) =>
        values.map((value) => quantityText(unscaleVolumeChartValue(value))),
    },
  })
  priceChart.priceScale('volume').applyOptions({ scaleMargins: { top: 0.8, bottom: 0 } })

  priceChart.timeScale().subscribeVisibleLogicalRangeChange((range: LogicalRange | null) => {
    if (!range || loadingMore || !hasMore || suppressLoadMore) return
    if (range.from < 0) {
      loadMorePrices()
    }
  })

  priceChart.subscribeCrosshairMove((param) => {
    if (!param.time || !priceSeries) {
      hoveredCandle.value = null
      return
    }
    const data = param.seriesData.get(priceSeries) as CandlestickData | SingleValueData | undefined
    if (!data) {
      hoveredCandle.value = null
      return
    }
    const vol = volumeSeries ? param.seriesData.get(volumeSeries) as { value?: number } | undefined : undefined
    if ('open' in data) {
      hoveredCandle.value = {
        o: unscalePriceChartValue(data.open),
        h: unscalePriceChartValue(data.high),
        l: unscalePriceChartValue(data.low),
        c: unscalePriceChartValue(data.close),
        v: vol?.value != null ? unscaleVolumeChartValue(vol.value) : 0,
        t: new Date((data.time as number) * 1000).toLocaleString(),
      }
    } else {
      hoveredCandle.value = {
        o: unscalePriceChartValue(data.value),
        h: unscalePriceChartValue(data.value),
        l: unscalePriceChartValue(data.value),
        c: unscalePriceChartValue(data.value),
        v: vol?.value != null ? unscaleVolumeChartValue(vol.value) : 0,
        t: new Date((data.time as number) * 1000).toLocaleString(),
      }
    }
  })

  resizeObserver = new ResizeObserver((entries) => {
    if (!priceChart) return
    for (const entry of entries) {
      const { width, height } = entry.contentRect
      priceChart.applyOptions({ width, height })
    }
  })
  resizeObserver.observe(container)
}

function applyPriceSeries(mode: 'line' | 'candlestick') {
  if (!priceChart) return
  if (priceSeries) {
    priceChart.removeSeries(priceSeries)
    priceSeries = null
  }
  const priceFormat = {
    type: 'custom' as const,
    minMove: LIGHTWEIGHT_CHART_MIN_MOVE,
    formatter: (value: number) => priceText(unscalePriceChartValue(value)),
    tickmarksFormatter: (values: readonly number[]) =>
      values.map((value) => priceText(unscalePriceChartValue(value))),
  }
  if (mode === 'candlestick') {
    priceSeries = priceChart.addSeries(CandlestickSeries, {
      priceFormat,
      upColor: '#2ecc71',
      downColor: '#ff5a8a',
      wickUpColor: '#2ecc71',
      wickDownColor: '#ff5a8a',
      borderVisible: false,
    })
  } else {
    priceSeries = priceChart.addSeries(AreaSeries, {
      priceFormat,
      lineColor: '#ff5a8a',
      topColor: 'rgba(255,90,138,0.35)',
      bottomColor: 'rgba(255,90,138,0.02)',
      lineWidth: 2,
    })
  }
}

function deduplicateTimeSeries<T extends { time: any }>(data: T[]): T[] {
  const map = new Map<any, T>()
  for (const item of data) {
    map.set(item.time, item)
  }
  return Array.from(map.values()).sort((a, b) => (a.time as number) - (b.time as number))
}

function applyPriceData(fit = true) {
  if (!priceChart || !priceSeries) return
  // Suppress load-more during setData/fitContent — both fire visible range change
  suppressLoadMore = true
  // Save visible time range to restore after setData (which resets the view)
  const savedRange = !fit ? priceChart.timeScale().getVisibleRange() : null
  const pts = filteredPrices.value
  if (viewMode.value === 'candlestick') {
    const candles: CandlestickData[] = pts.map((p) => ({
      time: toTime(p.created_at),
      open: scalePriceChartValue(p.open ?? p.close),
      high: scalePriceChartValue(p.high ?? p.close),
      low: scalePriceChartValue(p.low ?? p.close),
      close: scalePriceChartValue(p.close),
    }))
    ;(priceSeries as ISeriesApi<'Candlestick'>).setData(deduplicateTimeSeries(candles))
  } else {
    const line: SingleValueData[] = pts.map((p) => ({
      time: toTime(p.created_at),
      value: scalePriceChartValue(p.close),
    }))
    ;(priceSeries as ISeriesApi<'Area'>).setData(deduplicateTimeSeries(line))
  }

  if (volumeSeries) {
    const volumes: HistogramData[] = pts.map((p) => ({
      time: toTime(p.created_at),
      value: scaleVolumeChartValue(quantityNumber(p.volume)),
      color: (p.close >= (p.open ?? p.close)) ? '#2ecc71' : '#ff5a8a',
    }))
    volumeSeries.setData(deduplicateTimeSeries(volumes))
  }

  if (fit) {
    priceChart.timeScale().fitContent()
  } else if (savedRange) {
    priceChart.timeScale().setVisibleRange(savedRange)
  }
  setTimeout(() => { suppressLoadMore = false }, 500)
}

function syncPriceChartData(fit = true) {
  if (isDepthView()) return

  if (priceChartInteracting) {
    // Preserve the current viewport if any deferred update came from load-more.
    deferredPriceChartFit = deferredPriceChartFit === null ? fit : deferredPriceChartFit && fit
    return
  }

  if (!priceChart || !priceSeries) {
    const nextMode = viewMode.value === 'candlestick' ? 'candlestick' : 'line'
    void refreshPriceChart(nextMode, fit)
    return
  }

  applyPriceData(fit)
}

async function refreshPriceChart(mode: 'line' | 'candlestick', fit = true) {
  if (isDepthView()) return
  await nextTick()
  if (!priceChartContainer.value) return
  if (!priceChart) {
    setupPriceChart()
  }
  applyPriceSeries(mode)
  applyPriceData(fit)
}

function depthStepEpsilon(left: number, right: number): number {
  const span = Math.abs(right - left)
  if (!Number.isFinite(span) || span <= 0) return 0.0001
  return Math.min(span / 4, 0.0001)
}

type DepthChartPoint = SingleValueData<number>
type DepthChartSegment = DepthChartPoint[]
type DepthVisibleRange = { min: number; max: number } | null

function depthGapThreshold(levels: DepthLevel[], visibleRange: DepthVisibleRange): number {
  if (levels.length < 2) return Number.POSITIVE_INFINITY

  const visibleSpan = visibleRange ? visibleRange.max - visibleRange.min : 0
  const spanThreshold = visibleSpan > 0 ? visibleSpan * 0.015 : Number.POSITIVE_INFINITY
  const referencePrice = Math.abs(toApproxPrice(levels[Math.floor(levels.length / 2)]?.price ?? levels[0]?.price ?? 0))
  const relativeThreshold = referencePrice > 0 ? referencePrice * 0.01 : 0
  if (levels.length <= 4) {
    return Math.max(spanThreshold, relativeThreshold)
  }

  const gaps = levels
    .slice(1)
    .map((level, index) => Math.abs(toApproxPrice(level.price) - toApproxPrice(levels[index].price)))
    .filter((gap) => Number.isFinite(gap) && gap > 0)
    .sort((left, right) => left - right)

  if (gaps.length === 0) return Number.POSITIVE_INFINITY

  const medianGap = gaps[Math.floor(gaps.length / 2)]
  return Math.max(medianGap * 8, spanThreshold, relativeThreshold)
}

function pushDepthPoint(
  points: DepthChartPoint[],
  time: number,
  value: number,
) {
  const previousTime = points.length > 0 ? Number(points[points.length - 1].time) : null
  let nextTime = Number(time)
  if (previousTime != null && nextTime <= previousTime) {
    nextTime = previousTime + Math.max(
      DEPTH_CHART_MIN_TIME_STEP,
      Number.EPSILON * Math.max(1, Math.abs(previousTime)) * 32,
    )
  }
  points.push({
    time: nextTime,
    value,
  })
}

function isolatedDepthSegmentWidth(price: number, nextPrice: number | null, visibleRange: DepthVisibleRange): number {
  const visibleSpan = visibleRange ? visibleRange.max - visibleRange.min : Math.max(1, Math.abs(price))
  const preferredWidth = Math.max(visibleSpan * 0.002, Math.abs(price) * 0.000001, 0.0001)
  if (nextPrice == null) return preferredWidth
  const gap = Math.abs(nextPrice - price)
  if (!Number.isFinite(gap) || gap <= 0) return preferredWidth
  return Math.min(preferredWidth, gap * 0.1)
}

function ensureRenderableDepthSegment(
  points: DepthChartSegment,
  price: number,
  nextPrice: number | null,
  visibleRange: DepthVisibleRange,
) {
  if (points.length !== 1) return
  pushDepthPoint(
    points,
    scaleDepthPriceChartValue(price + isolatedDepthSegmentWidth(price, nextPrice, visibleRange)),
    points[0].value,
  )
}

function buildDepthSegments(
  midPrice: NumericLike,
  levels: DepthLevel[],
  side: 'bid' | 'ask',
  visibleRange: DepthVisibleRange,
): DepthChartSegment[] {
  const approxMidPrice = toApproxPrice(midPrice)
  const orderedLevels = side === 'bid' ? [...levels].reverse() : levels
  const emptySegment: DepthChartSegment = []
  if (orderedLevels.length === 0) {
    pushDepthPoint(emptySegment, scaleDepthPriceChartValue(approxMidPrice), 0)
    ensureRenderableDepthSegment(emptySegment, approxMidPrice, null, visibleRange)
    return [emptySegment]
  }

  const segments: DepthChartSegment[] = []
  const gapThreshold = depthGapThreshold(orderedLevels, visibleRange)
  let currentSegment: DepthChartSegment = []

  pushDepthPoint(
    currentSegment,
    scaleDepthPriceChartValue(toApproxPrice(orderedLevels[0].price)),
    scaleDepthQuantityChartValue(orderedLevels[0].quantity),
  )

  for (let index = 1; index < orderedLevels.length; index += 1) {
    const previous = orderedLevels[index - 1]
    const current = orderedLevels[index]
    const gap = Math.abs(toApproxPrice(current.price) - toApproxPrice(previous.price))

    if (gap > gapThreshold) {
      ensureRenderableDepthSegment(currentSegment, toApproxPrice(previous.price), toApproxPrice(current.price), visibleRange)
      segments.push(currentSegment)
      currentSegment = []
      pushDepthPoint(
        currentSegment,
        scaleDepthPriceChartValue(toApproxPrice(current.price)),
        scaleDepthQuantityChartValue(current.quantity),
      )
      continue
    }

    const epsilon = depthStepEpsilon(toApproxPrice(previous.price), toApproxPrice(current.price))
    pushDepthPoint(
      currentSegment,
      scaleDepthPriceChartValue(toApproxPrice(current.price) - epsilon),
      scaleDepthQuantityChartValue(previous.quantity),
    )
    pushDepthPoint(
      currentSegment,
      scaleDepthPriceChartValue(toApproxPrice(current.price)),
      scaleDepthQuantityChartValue(current.quantity),
    )
  }

  ensureRenderableDepthSegment(currentSegment, toApproxPrice(orderedLevels[orderedLevels.length - 1].price), null, visibleRange)
  segments.push(currentSegment)
  return segments
}

function createDepthAreaSeries(chart: IChartApiBase<number>, side: 'bid' | 'ask'): ISeriesApi<'Area', number> {
  return chart.addSeries(AreaSeries, {
    lineWidth: 2,
    priceLineVisible: false,
    lastValueVisible: false,
    crosshairMarkerVisible: false,
    priceFormat: {
      type: 'custom',
      minMove: LIGHTWEIGHT_CHART_MIN_MOVE,
      formatter: (value: number) => depthAxisQuantityLabel(value),
      tickmarksFormatter: (values: readonly number[]) => values.map((value) => depthAxisQuantityLabel(value)),
    },
    ...(side === 'bid'
      ? {
          lineColor: '#3fb950',
          topColor: 'rgba(63, 185, 80, 0.22)',
          bottomColor: 'rgba(63, 185, 80, 0.04)',
        }
      : {
          lineColor: '#ff3860',
          topColor: 'rgba(255, 56, 96, 0.22)',
          bottomColor: 'rgba(255, 56, 96, 0.04)',
        }),
  })
}

function syncDepthAreaSeries(side: 'bid' | 'ask', targetCount: number) {
  if (!depthChart) return

  const seriesList = side === 'bid' ? depthBidSeriesList : depthAskSeriesList
  while (seriesList.length < targetCount) {
    seriesList.push(createDepthAreaSeries(depthChart, side))
  }
  while (seriesList.length > targetCount) {
    const series = seriesList.pop()
    if (series) {
      depthChart.removeSeries(series)
    }
  }
}

function getHoveredDepthSeriesData(
  param: Parameters<IChartApiBase<number>['subscribeCrosshairMove']>[0] extends (arg: infer T) => void ? T : never,
  seriesList: ISeriesApi<'Area', number>[],
): SingleValueData<number> | null {
  for (const series of seriesList) {
    const data = param.seriesData.get(series) as SingleValueData<number> | undefined
    if (data) return data
  }
  return null
}

function setupDepthChart() {
  const container = depthChartContainer.value
  if (!container) return

  destroyDepthChart()

  const chart = createOptionsChart(container, {
    height: container.clientHeight,
    width: container.clientWidth,
    layout: {
      background: { type: ColorType.Solid, color: 'transparent' },
      textColor: '#8e8e9d',
    },
    localization: {
      locale: 'en-US',
      precision: 2,
      timeFormatter: (value: number) => priceText(unscaleDepthPriceChartValue(value)),
      priceFormatter: (value: number) => depthAxisQuantityLabel(value),
      tickmarksPriceFormatter: (values: readonly number[]) => values.map((value) => depthAxisQuantityLabel(value)),
    },
    grid: {
      vertLines: { color: 'rgba(50,50,62,0.5)' },
      horzLines: { color: 'rgba(50,50,62,0.5)' },
    },
    crosshair: {
      mode: CrosshairMode.Normal,
    },
    timeScale: {
      borderColor: '#32323e',
    },
    rightPriceScale: {
      borderColor: '#32323e',
      scaleMargins: { top: 0.1, bottom: 0.05 },
    },
  })
  depthChart = chart
  depthBidSeriesList = [createDepthAreaSeries(chart, 'bid')]
  depthAskSeriesList = [createDepthAreaSeries(chart, 'ask')]

  chart.subscribeCrosshairMove((param) => {
    const point = param.point
    if (!point || !container || depthBidSeriesList.length === 0 || depthAskSeriesList.length === 0) {
      hoveredDepthPoint.value = null
      return
    }

    const askData = getHoveredDepthSeriesData(param, depthAskSeriesList)
    const bidData = getHoveredDepthSeriesData(param, depthBidSeriesList)
    const activeData = askData ?? bidData

    if (!activeData) {
      hoveredDepthPoint.value = null
      return
    }

    const hoveredPrice = unscaleDepthPriceChartValue(activeData.time)

    hoveredDepthPoint.value = {
      side: askData ? 'ask' : 'bid',
      price: hoveredPrice,
      quantity: unscaleDepthQuantityChartValue(activeData.value),
      amount: hoveredPrice * unscaleDepthQuantityChartValue(activeData.value),
    }
  })

  depthResizeObserver = new ResizeObserver((entries) => {
    if (!depthChart) return
    for (const entry of entries) {
      const { width, height } = entry.contentRect
      depthChart.resize(width, height)
    }
  })
  depthResizeObserver.observe(container)
}

const savedDepthRange = Number(localStorage.getItem('turnip_depth_range'))
const depthRange = ref<number>([25, 50, 100, 0].includes(savedDepthRange) ? savedDepthRange : 50)
const depthLogScale = ref(localStorage.getItem('turnip_depth_log_scale') === '1')

// Compute visible price range: symmetric percentage around mid_price (0 = show all)
const depthPriceRange = computed<{ min: number; max: number } | null>(() => {
  if (!depthData.value) return null
  const d = depthData.value
  const mid = toApproxPrice(d.mid_price)
  if (depthRange.value === 0) {
    // Show all: use full data extent
    const lo = d.bids.length ? toApproxPrice(d.bids[d.bids.length - 1].price) : mid * 0.5
    const hi = d.asks.length ? toApproxPrice(d.asks[d.asks.length - 1].price) : mid * 1.5
    const span = Math.max(mid - lo, hi - mid) * 1.05
    return { min: Math.max(0, mid - span), max: mid + span }
  }
  const span = mid * (depthRange.value / 100)
  return { min: Math.max(0, mid - span), max: mid + span }
})

const visibleDepthLevels = computed<{ bids: DepthLevel[]; asks: DepthLevel[] }>(() => {
  if (!depthData.value || !depthPriceRange.value) {
    return { bids: [], asks: [] }
  }

  const { min, max } = depthPriceRange.value
  return {
    bids: depthData.value.bids.filter((level) => toApproxPrice(level.price) >= min),
    asks: depthData.value.asks.filter((level) => toApproxPrice(level.price) <= max),
  }
})

function scaleDepthValue(value: NumericLike): number {
  const numericValue = Math.max(0, quantityNumber(value))
  return depthLogScale.value ? Math.log1p(numericValue) : numericValue
}

function scaleDepthRatio(value: NumericLike, total: NumericLike): number {
  if (!depthLogScale.value) {
    return divideIntegerLike(value, total)
  }

  const scaledTotal = scaleDepthValue(total)
  if (scaledTotal <= 0) return 0
  return scaleDepthValue(value) / scaledTotal
}

function depthAxisQuantityLabel(value: number): string {
  if (!Number.isFinite(value) || value < 0) return ''
  return compactQtyText(unscaleDepthQuantityChartValue(value))
}

function buildOrderBookRows(levels: DepthLevel[]): OrderBookRow[] {
  const sideTotal = levels.length > 0 ? levels[levels.length - 1].quantity : 0
  let previousQuantity: NumericLike = 0

  return levels.map((level) => {
    const cumulative = level.quantity
    const amount = subtractIntegerLike(cumulative, previousQuantity)
    previousQuantity = cumulative

    return {
      price: level.price,
      amount,
      total: toApproxPrice(level.price) * quantityNumber(amount),
      cumulative,
      cumulativeWidth: scaleDepthRatio(cumulative, sideTotal) * 100,
    }
  })
}

const orderBookAsks = computed<OrderBookRow[]>(() => buildOrderBookRows(visibleDepthLevels.value.asks))
const orderBookBids = computed<OrderBookRow[]>(() => buildOrderBookRows(visibleDepthLevels.value.bids))

const orderBookAskTotal = computed<NumericLike>(() => {
  const rows = orderBookAsks.value
  return rows.length > 0 ? rows[rows.length - 1].cumulative : 0
})

const orderBookBidTotal = computed<NumericLike>(() => {
  const rows = orderBookBids.value
  return rows.length > 0 ? rows[rows.length - 1].cumulative : 0
})

const orderBookTotal = computed<NumericLike>(() => addIntegerLike(orderBookAskTotal.value, orderBookBidTotal.value))

const orderBookAskShare = computed(() => divideIntegerLike(orderBookAskTotal.value, orderBookTotal.value))

const orderBookBidShare = computed(() => divideIntegerLike(orderBookBidTotal.value, orderBookTotal.value))

const orderBookMidPrice = computed(() => depthData.value?.mid_price ?? market.value?.current_price ?? 0)

const depthQuantityChartScaleFactor = computed(() => {
  if (!depthData.value) return 1

  let maxAbs = 0
  for (const level of depthData.value.bids) {
    maxAbs = Math.max(maxAbs, Math.abs(scaleDepthValue(level.quantity)))
  }
  for (const level of depthData.value.asks) {
    maxAbs = Math.max(maxAbs, Math.abs(scaleDepthValue(level.quantity)))
  }

  return getLightweightChartScaleFactor(maxAbs)
})

function scaleDepthQuantityChartValue(value: NumericLike): number {
  return scaleChartValue(scaleDepthValue(value), depthQuantityChartScaleFactor.value)
}

function applyDepthChartData() {
  if (!depthChart || !depthData.value || !depthPriceRange.value) return

  const visibleRange = depthPriceRange.value
  const midPrice = toApproxPrice(depthData.value.mid_price)
  const bidSegments = buildDepthSegments(midPrice, visibleDepthLevels.value.bids, 'bid', visibleRange)
  const askSegments = buildDepthSegments(midPrice, visibleDepthLevels.value.asks, 'ask', visibleRange)

  syncDepthAreaSeries('bid', bidSegments.length)
  syncDepthAreaSeries('ask', askSegments.length)

  depthBidSeriesList.forEach((series, index) => {
    series.setData(bidSegments[index] ?? [])
  })
  depthAskSeriesList.forEach((series, index) => {
    series.setData(askSegments[index] ?? [])
  })

  depthChart.timeScale().setVisibleRange({
    from: scaleDepthPriceChartValue(depthPriceRange.value.min),
    to: scaleDepthPriceChartValue(depthPriceRange.value.max),
  })
}

function syncDepthChartData() {
  if (!isDepthChartMode()) return
  if (!depthChart || depthBidSeriesList.length === 0 || depthAskSeriesList.length === 0) {
    void refreshDepthChart()
    return
  }
  applyDepthChartData()
}

async function refreshDepthChart() {
  if (!isDepthChartMode()) return
  await nextTick()
  if (!depthChartContainer.value) return
  if (!depthChart) {
    setupDepthChart()
  }
  applyDepthChartData()
}

