async function fetchMarket() {
  try {
    marketError.value = null
    const interval = getIntervalMinutes()
    const [marketRes, pricesRes] = await Promise.all([
      api.get<MarketData>('/api/turnip/market'),
      api.get<{ prices: PricePoint[] }>('/api/turnip/prices', {
        params: { hours: timeRange.value, interval_minutes: interval },
      }),
    ])
    market.value = normalizeMarketData(marketRes.data)
    prices.value = pricesRes.data.prices.map(normalizePricePoint)
    hasMore = true
  } catch (e: unknown) {
    marketError.value = e instanceof Error ? e.message : '加载失败'
  } finally {
    marketLoading.value = false
  }
}

let pendingLoadMore = false

async function loadMorePrices() {
  if (loadingMore || !hasMore || prices.value.length === 0) return
  loadingMore = true
  try {
    const oldest = prices.value[0].created_at
    const interval = getIntervalMinutes()
    const response = await api.get<{ prices: PricePoint[] }>('/api/turnip/prices', {
      params: { hours: timeRange.value, interval_minutes: interval, before: oldest },
    })
    const older = response.data.prices.map(normalizePricePoint)
    if (older.length === 0) {
      hasMore = false
      return
    }
    // Flag so the filteredPrices watcher uses fit=false
    pendingLoadMore = true
    prices.value = [...older, ...prices.value]
  } catch {
    // load-more is supplementary — fail silently
  } finally {
    loadingMore = false
  }
}

