  }
}

async function cancelInsurance(policyId: number) {
  const policy = activePolicies.value.find((item) => item.id === policyId)
  if (!isAuthenticated.value || insuranceCancelling.value !== null || !policy) return
  insuranceActionError.value = null
  insuranceActionSuccess.value = null

  let previewRefund = cancelRefundQuotes.value.get(policyId) ?? null
  if (previewRefund === null || previewRefund === undefined) {
    previewRefund = await fetchCancelRefundQuote(policy)
  }
  if (previewRefund === null || previewRefund === undefined) {
    insuranceActionError.value = '无法获取当前退款预估，请稍后再试'
    return
  }

  const confirmed = await showConfirm({
    message: `确定要退保保单 #${policyId}？\n种子 #${policy.seed_id} · ${modeLabel(policy.mode)}\n预计可退: ≈ ${priceText(previewRefund)}`,
    danger: true,
  })
  if (!confirmed) return

  insuranceCancelling.value = policyId
  try {
    const { data } = await api.post<InsuranceCancelResponse>(`/api/turnip/insurance/cancel/${policyId}`)
    if (!data.success) {
      insuranceActionError.value = data.error || '退保失败'
    } else {
      insuranceActionSuccess.value = `退保成功！退款 ${priceText(data.refund ?? 0)}`
      await Promise.all([fetchInsurancePolicies(), fetchBalance(), fetchInsuranceTreasury()])
    }
  } catch (error: unknown) {
    insuranceActionError.value = parseErrorMessage(error, '退保失败')
  } finally {
    insuranceCancelling.value = null
  }
}

function insuranceExpiryRemaining(expiresAt: string): string {
  const remaining = new Date(expiresAt).getTime() - Date.now()
  if (remaining <= 0) return '待结算'
  const hours = Math.floor(remaining / 3600000)
  const minutes = Math.floor((remaining % 3600000) / 60000)
  return hours > 0 ? `${hours}h${minutes}m` : `${minutes}m`
}

function insurancePnlBreakdown(seed: SeedBatch, quote: InsuranceQuoteResponse) {
  // Total cost = seed investment + premium
  const seedCost = seed.total_cost ?? (seed.seed_price * toNumber(seed.quantity))
  const premium = quote.total_premium ?? 0
  const totalCost = seedCost + premium

  // Guaranteed floor income = strike * coverage_qty
  const strike = quote.strike ?? 0
  const coverageQty = toNumber(quote.coverage_qty ?? 0)
  const floorIncome = strike * coverageQty

  // Breakeven sell price per turnip (total cost / coverage qty)
  const breakeven = coverageQty > 0 ? totalCost / coverageQty : 0

  // P&L ratio for the bar visualization
  const pnlRatio = totalCost > 0 ? floorIncome / totalCost : 0

  return { totalCost, premium, floorIncome, breakeven, pnlRatio }
}

// Cancel refund quotes for American policies (fetched on demand)
const cancelRefundQuotes = ref<Map<number, number>>(new Map())

async function fetchCancelRefundQuote(policy: InsurancePolicy): Promise<number | null> {
  if (policy.mode !== 'american' || policy.status !== 'active') return null
  try {
    const { data } = await api.get<InsuranceCancelPreviewResponse>(
      `/api/turnip/insurance/cancel-preview/${policy.id}`,
    )
    const preview = normalizeInsuranceCancelPreview(data)
    if (preview.success && preview.refund != null) {
      cancelRefundQuotes.value.set(policy.id, preview.refund)
      return preview.refund
    }
  } catch {
    // Silent fail
  }
  return null
}

async function refreshCancelRefundQuotes() {
  for (const policy of activePolicies.value) {
    if (policy.mode === 'american') {
      await fetchCancelRefundQuote(policy)
    }
  }
}

function insuranceExpiryPercent(policy: InsurancePolicy): number {
  const total = new Date(policy.expires_at).getTime() - new Date(policy.purchased_at).getTime()
  const elapsed = Date.now() - new Date(policy.purchased_at).getTime()
  return Math.min(100, Math.max(0, (elapsed / total) * 100))
}

