async function submitTurnipBuy() {
  if (!isAuthenticated.value) return

  const rawInput = buyQuantity.value.trim()
  if (!rawInput) {
    turnipTradeError.value = '请输入买入数量或金额'
    return
  }

  const isAmount = rawInput.startsWith('$') || rawInput.startsWith('￥') || rawInput.startsWith('¥')
  const payload: { quantity?: string; amount?: string } = {}

  if (isAmount) {
    const amount = parseAmount(rawInput)
    if (amount === null) {
      turnipTradeError.value = '请输入有效买入金额，例如 $10000'
      return
    }
    payload.amount = amount
  } else {
    const quantity = parseQuantityString(rawInput)
    if (quantity === null) {
      turnipTradeError.value = '请输入有效买入数量'
      return
    }
    payload.quantity = quantity
  }

  turnipTradeSubmitting.value = true
  turnipTradeError.value = null
  turnipTradeSuccess.value = null

  try {
    const slippagePct = normalizeExactDecimalString(buySlippage.value)
    if (market.value && slippagePct && compareExactDecimals(slippagePct, '0') !== -1) {
      const ask = normalizeExactDecimalString(market.value.ask)
      if (ask !== null) {
        ;(payload as Record<string, unknown>).max_price = exactDecimalToBig(ask)
          .times(exactDecimalToBig('1').plus(exactDecimalToBig(slippagePct).div('100')))
          .toFixed(2)
      }
    }
    const response = await api.post<TurnipTradeResponse>('/api/turnip/buy', payload)
    const result = normalizeTurnipTradeResponse(response.data)
    if (!result.success) {
      turnipTradeError.value = result.error || '买入失败'
      return
    }

    if (result.new_balance !== undefined && result.new_balance !== null) {
      balance.value = result.new_balance
      balanceLoading.value = false
    }

    turnipTradeSuccess.value = `买入成功：${quantityText(result.quantity)} 个，均价 ${priceText(result.unit_price)}`
    await Promise.all([
      fetchMarket(),
      fetchInventory(),
    ])
  } catch (error: unknown) {
    turnipTradeError.value = parseErrorMessage(error, '买入失败')
  } finally {
    turnipTradeSubmitting.value = false
  }
}

async function submitTurnipSell(sellAll: boolean) {
  if (!isAuthenticated.value || !inventory.value) return

  const effectiveSellAll = sellAll || sellQuantity.value.trim() === ''
  if (quantityNumber(inventory.value.settled_quantity) <= 0) {
    turnipTradeError.value = '当前没有可卖出的已交割大头菜'
    turnipTradeSuccess.value = null
    return
  }

  let quantity: string | undefined
  if (!effectiveSellAll) {
    quantity = parseQuantityString(sellQuantity.value) ?? '0'
    if (BigInt(quantity) <= 0n) {
      turnipTradeError.value = '请输入有效卖出数量'
      return
    }
  }

  turnipTradeSubmitting.value = true
  turnipTradeError.value = null
  turnipTradeSuccess.value = null

  try {
    const sellPayload: Record<string, unknown> = effectiveSellAll ? {} : { quantity }
    const slippagePct = normalizeExactDecimalString(sellSlippage.value)
    if (market.value && slippagePct && compareExactDecimals(slippagePct, '0') !== -1) {
      const bid = normalizeExactDecimalString(market.value.bid)
      if (bid !== null) {
        sellPayload.min_price = exactDecimalToBig(bid)
          .times(exactDecimalToBig('1').minus(exactDecimalToBig(slippagePct).div('100')))
          .toFixed(2)
      }
    }
    const response = await api.post<TurnipTradeResponse>(
      '/api/turnip/sell',
      sellPayload,
