async function submitFarmPlantAll() {
  if (!isAuthenticated.value || !farm.value || !inventory.value) return
  if (farmActionSubmitting.value !== null) return

  const available = farmAvailable.value
  if (available <= 0) {
    farmActionError.value = '当前没有可用农场容量'
    farmActionSuccess.value = null
    return
  }

  const inventoryTotal = quantityNumber(inventory.value.total_quantity)
  if (inventoryTotal <= 0) {
    farmActionError.value = '大头菜库存不足，请先购买后再种植'
    farmActionSuccess.value = null
    return
  }

  const quantity = Math.min(available, inventoryTotal * 3)
  if (!Number.isFinite(quantity) || quantity <= 0) {
    farmActionError.value = '大头菜库存不足，请先购买后再种植'
    farmActionSuccess.value = null
    return
  }

  plantQuantity.value = String(quantity)
  await submitFarmPlant()
}

