function integerLikeToSafeNumber(value: NumericLike | null | undefined): number | null {
  const integerString = asIntegerString(value)
  if (integerString === null) return null

  // Preview-only helper: clamp arbitrary-size integers before feeding them back
  // into JS-number math for approximate UI calculations like escrow previews.
  const quantity = Number(integerString)
  return Number.isSafeInteger(quantity) ? quantity : null
}

function resolveLimitQuantity(): NumericLike | null {
  const raw = limitQuantity.value.trim()
  if (!raw) return null
  const isAmount = raw.startsWith('$') || raw.startsWith('￥') || raw.startsWith('¥')
  if (isAmount) {
    return parseQuantityFromAmount(raw, limitPrice.value)
  }
  return parseQuantityString(raw)
}

const escrowEstimate = computed(() => {
  const qty = resolveLimitQuantity()
  const price = parseAmount(limitPrice.value)
  const safeQty = integerLikeToSafeNumber(qty)
  // Hide the estimate once quantity exceeds MAX_SAFE_INTEGER; submission still
  // uses the exact bigint-string path below.
  const approxPrice = exactToApproxNumber(price)
  if (safeQty === null || approxPrice === null || approxPrice <= 0) return null
  return safeQty * approxPrice
})


function formatTimeRemaining(expiresAt: string): string {
  const diff = new Date(expiresAt).getTime() - Date.now()
  if (diff <= 0) return '已过期'
  const hours = Math.floor(diff / 3_600_000)
  if (hours >= 24) return `${Math.floor(hours / 24)}天${hours % 24}小时`
  const mins = Math.floor((diff % 3_600_000) / 60_000)
  if (hours > 0) return `${hours}小时${mins}分`
  return `${mins}分钟`
}

