async function submitLimitOrder() {
  if (!isAuthenticated.value || orderSubmitting.value) return

  const price = parseAmount(limitPrice.value)
  if (price === null) {
    orderError.value = '请输入有效限价'
    return
  }

  const qty = resolveLimitQuantity()
  const quantity = asIntegerString(qty)
  if (quantity === null || BigInt(quantity) <= 0n) {
    orderError.value = '请输入有效数量（支持K/M/万/亿后缀，或$金额自动换算）'
    return
  }

  orderSubmitting.value = true
  orderError.value = null
  orderSuccess.value = null

  try {
    const res = await api.post<OrderCreateResponse>('/api/turnip/order', {
      side: limitSide.value,
      quantity,
      limit_price: price,
    })
    const order = normalizeOrderCreateResponse(res.data)
    const sideLabel = order.side === 'buy' ? '买' : '卖'
    toast.success(`限价${sideLabel}单 #${order.id} 已挂出`)
    orderSuccess.value = `限价${sideLabel}单已挂出：${quantityText(quantity)} 个 @ ${priceText(price)}`
    limitQuantity.value = ''
    limitPrice.value = ''
    await Promise.all([fetchOrders(), fetchBalance(), fetchInventory()])
  } catch (error: unknown) {
    orderError.value = parseErrorMessage(error, '挂单失败')
  } finally {
    orderSubmitting.value = false
  }
}

async function cancelOrder(order: Order) {
  const sideLabel = order.side === 'buy' ? '买' : '卖'
  const confirmed = await showConfirm({
    message: `确定要取消限价${sideLabel}单 #${order.id}？\n数量: ${quantityText(order.remaining)} 个 @ ${priceText(order.limit_price)}`,
    danger: true,
  })
  if (!confirmed) return

  try {
    const res = await api.delete<CancelOrderResponse>(`/api/turnip/order/${order.id}`)
    const result = normalizeCancelOrderResponse(res.data)
    if (result.success) {
      const refundText =
        order.side === 'buy' && result.refund_amount ? `，退还 ${priceText(result.refund_amount)}` : ''
      toast.success(`订单 #${order.id} 已取消${refundText}`)
    } else {
      toast.error(result.error || '取消失败')
    }
    await Promise.all([fetchOrders(), fetchBalance(), fetchInventory()])
  } catch (error: unknown) {
    toast.error(parseErrorMessage(error, '取消失败'))
  }
}

