// Real-time tick update via SSE
watch(turnipTick, (tick) => {
  if (!tick || !market.value) return
  const midPrice = coerceFiniteNumber(tick.mid_price)
  if (midPrice === null) return

  if (market.value.current_price !== midPrice) {
    scheduleTickAnimatedField('current_price')
  }
  market.value.current_price = midPrice

  if (tick.bid != null) {
    const bid = coerceFiniteNumber(tick.bid)
    if (bid !== null) {
      if (market.value.bid !== bid) {
        scheduleTickAnimatedField('bid')
      }
      market.value.bid = bid
    }
  }
  if (tick.ask != null) {
    const ask = coerceFiniteNumber(tick.ask)
    if (ask !== null) {
      if (market.value.ask !== ask) {
        scheduleTickAnimatedField('ask')
      }
      market.value.ask = ask
    }
  }
  if (tick.inventory !== undefined) {
    if (market.value.treasury_turnip_balance !== tick.inventory) {
      scheduleTickAnimatedField('treasury_turnip_balance')
    }
    market.value.treasury_turnip_balance = tick.inventory
  }
  const liveDepth = normalizeDepthDataFromTick(tick)
  if (liveDepth) {
    depthData.value = liveDepth
  } else if (isDepthView()) {
    void fetchDepth()
  }
  if (tick.bid == null || tick.ask == null) {
    void fetchMarket()
  }

  // Prepend new trades using the full trade identity so same-timestamp fills are preserved.
  let tickVolume = 0
  let tickTradeCount = 0
  if (tick.recent_trades.length > 0) {
    const existingTradeKeys = new Set(market.value.recent_trades.map(recentTradeIdentity))
    const newTrades = tick.recent_trades.filter((trade) => !existingTradeKeys.has(recentTradeIdentity(trade)))
    if (newTrades.length > 0) {
      market.value.recent_trades = sortRecentTradesNewestFirst(
        [...newTrades, ...market.value.recent_trades],
      ).slice(0, 50)
      tickVolume = newTrades.reduce((sum, t) => sum + quantityNumber(t.qty), 0)
      for (const trade of newTrades) {
        scheduleRecentTradeAnimation(trade)
      }
      tickVolume = newTrades.reduce((sum, t) => sum + quantityNumber(t.qty), 0)
      tickTradeCount = newTrades.length
    }
  }

  // Live-update K-line chart with current price
  if (priceSeries && prices.value.length > 0 && !isDepthView()) {
    const previousPriceScaleFactor = priceChartValueScaleFactor.value
    const previousVolumeScaleFactor = volumeChartValueScaleFactor.value
    const price = midPrice
    const intervalMs = getIntervalMinutes() * 60_000
    const last = prices.value[prices.value.length - 1]
    const lastBucket = Math.floor(new Date(last.created_at).getTime() / intervalMs)
    const tickBucket = Math.floor(new Date(tick.updated_at).getTime() / intervalMs)

    let candle: PricePoint
    if (tickBucket > lastBucket) {
      // New time period — append a new candle
      const newTs = new Date(tickBucket * intervalMs).toISOString()
      candle = {
        open: price, high: price, low: price, close: price,
        volume: tickVolume, trade_count: tickTradeCount, trend: '', trend_tick: 0,
        created_at: newTs,
      }
      prices.value.push(candle)
    } else {
      // Same period — update existing candle
      candle = last
      candle.close = price
      candle.high = Math.max(candle.high ?? candle.close, price)
      candle.low = Math.min(candle.low ?? candle.close, price)
      candle.volume = quantityNumber(candle.volume) + tickVolume
      candle.trade_count += tickTradeCount
    }

    const nextPriceScaleFactor = priceChartValueScaleFactor.value
    const nextVolumeScaleFactor = volumeChartValueScaleFactor.value
    if (nextPriceScaleFactor !== previousPriceScaleFactor || nextVolumeScaleFactor !== previousVolumeScaleFactor) {
      syncPriceChartData()
      return
    }

    const t = toTime(candle.created_at)
    if (viewMode.value === 'candlestick') {
      ;(priceSeries as ISeriesApi<'Candlestick'>).update({
        time: t,
        open: scalePriceChartValue(candle.open ?? candle.close),
        high: scalePriceChartValue(candle.high ?? candle.close),
        low: scalePriceChartValue(candle.low ?? candle.close),
        close: scalePriceChartValue(candle.close),
      })
    } else {
      ;(priceSeries as ISeriesApi<'Area'>).update({ time: t, value: scalePriceChartValue(candle.close) })
    }
    if (volumeSeries) {
      volumeSeries.update({
        time: t,
        value: scaleVolumeChartValue(quantityNumber(candle.volume)),
        color: candle.close >= (candle.open ?? candle.close) ? '#2ecc71' : '#ff5a8a',
      })
    }
  }
})

watch(timeRange, async () => {
  localStorage.setItem('turnip_chart_time_range', String(timeRange.value))
  await fetchMarket()
