watch(depthChartContainer, (container) => {
  if (container && isDepthChartMode()) {
    void refreshDepthChart()
  }
}, { flush: 'post' })

watch(viewMode, (mode) => {
  localStorage.setItem('turnip_chart_mode', mode)
  if (mode === 'depth') {
    destroyPriceChart()
    if (!depthData.value) {
      void fetchDepth()
    }
    void refreshDepthChart()
  } else if (mode === 'orderbook') {
    destroyPriceChart()
    destroyDepthChart()
    if (!depthData.value) {
      void fetchDepth()
    }
  } else {
    destroyDepthChart()
    fetchMarket()
    void refreshPriceChart(mode)
  }
})

watch(filteredPrices, () => {
  if (!isDepthView()) {
    if (pendingLoadMore) {
      pendingLoadMore = false
      syncPriceChartData(false)
    } else {
      syncPriceChartData()
    }
  }
})

watch(activeTab, (newTab) => {
  if (newTab === 'transactions' && isAuthenticated.value && transactionsLoading.value) {
    fetchTransactions()
  }
  if (newTab === 'orders' && isAuthenticated.value && ordersLoading.value) {
    fetchOrders()
  }
})

watch(showAllOrders, () => {
  fetchOrders()
})

onUnmounted(() => {
  if (marketTimer) clearInterval(marketTimer)
  if (portfolioTimer) clearInterval(portfolioTimer)
  if (balanceTimer) clearInterval(balanceTimer)
  if (farmTimer) clearInterval(farmTimer)
  if (ordersTimer) clearInterval(ordersTimer)
  for (const timer of tickAnimatedFieldTimers.values()) clearTimeout(timer)
  for (const timer of recentTradeAnimationTimers.values()) clearTimeout(timer)
  tickAnimatedFieldTimers.clear()
  recentTradeAnimationTimers.clear()
  destroyPriceChart()
  destroyDepthChart()
})
