        <div class="mt-2 flex flex-wrap gap-x-4 gap-y-1 text-sm text-text-secondary">
          <span data-testid="market-ask" :class="tickAnimatedFieldClass('ask')">买入价 {{ priceText(market.ask) }}</span>
          <span data-testid="market-bid" :class="tickAnimatedFieldClass('bid')">卖出价 {{ priceText(market.bid) }}</span>
          <span>价差 {{ formatSpread(displayedSpreadPct) }}</span>
          <span data-testid="market-cash">系统现金 {{ currencyText(market.treasury_cash_balance) }}</span>
          <span data-testid="market-inventory" :class="tickAnimatedFieldClass('treasury_turnip_balance')">系统库存 {{ quantityText(market.treasury_turnip_balance) }}</span>
        </div>
