                :key="mode.key"
                class="px-3 py-1 rounded-md border text-[13px] cursor-pointer transition-all duration-150"
                :class="viewMode === mode.key
                  ? 'bg-accent text-white border-accent'
                  : 'border-border text-text-secondary bg-transparent hover:text-text-primary hover:border-text-secondary'"
                @click="viewMode = mode.key as 'line' | 'candlestick' | 'depth' | 'orderbook'"
              >
