              @click="refreshChart"
              title="刷新"
              aria-label="刷新"
            >
              <RotateCcw aria-hidden="true" class="w-3.5 h-3.5" :class="{ 'animate-spin': refreshing }" />
            </button>
          </div>
        </div>
        <div
          class="relative"
          :class="viewMode === 'orderbook' ? 'h-[500px] xs:h-[620px]' : 'h-[220px] xs:h-[300px]'"
