          <template v-if="viewMode === 'orderbook'">
            <div
              v-if="depthData"
              data-testid="order-book-panel"
              class="flex h-full flex-col overflow-hidden rounded-md border border-border/70 bg-bg-tertiary/20"
            >
              <div class="grid grid-cols-[minmax(0,1fr)_minmax(0,1fr)_minmax(0,1fr)] gap-3 border-b border-border/70 px-3 py-2 text-[11px] font-medium text-text-secondary">
