                <span class="text-right">数量</span>
                <span class="text-right">总额</span>
              </div>
              <div class="min-h-0 flex-1 overflow-y-auto px-2 py-2">
                <div class="space-y-1">
                  <div
                    v-for="(row, index) in orderBookAsks.slice().reverse()"
                    :key="`ask-${row.price}`"
                    :data-testid="`order-book-ask-row-${index}`"
                    class="relative grid grid-cols-[minmax(0,1fr)_minmax(0,1fr)_minmax(0,1fr)] items-center gap-3 overflow-hidden rounded-sm px-2 py-1 font-mono text-[13px] xs:text-sm"
                  >
                    <div
                      :data-testid="`order-book-ask-fill-${index}`"
                      class="absolute inset-y-0 right-0 rounded-sm bg-danger/14"
                      :style="{ width: `${row.cumulativeWidth}%` }"
                    ></div>
                    <span class="relative z-10 text-danger whitespace-nowrap">{{ priceText(row.price) }}</span>
                    <span class="relative z-10 text-right text-text-primary whitespace-nowrap">{{ quantityText(row.amount) }}</span>
                    <span class="relative z-10 text-right text-text-primary whitespace-nowrap">{{ currencyText(row.total) }}</span>
                  </div>

                  <div class="my-2 flex items-center justify-between gap-3 border-y border-border/70 bg-bg-primary/40 px-2 py-3">
                    <div data-testid="order-book-mid-price" class="font-mono text-[26px] font-semibold leading-none" :style="{ color: trendColor }">
                      {{ priceText(orderBookMidPrice) }}
                    </div>
                    <div class="text-right text-[11px] text-text-secondary">
                      <div>价差 {{ formatSpread(depthData.spread_pct) }}</div>
                      <div>总深度 {{ compactQtyText(depthData.depth) }}</div>
                    </div>
                  </div>

                  <div
                    v-for="(row, index) in orderBookBids"
                    :key="`bid-${row.price}`"
                    :data-testid="`order-book-bid-row-${index}`"
                    class="relative grid grid-cols-[minmax(0,1fr)_minmax(0,1fr)_minmax(0,1fr)] items-center gap-3 overflow-hidden rounded-sm px-2 py-1 font-mono text-[13px] xs:text-sm"
                  >
                    <div
                      :data-testid="`order-book-bid-fill-${index}`"
                      class="absolute inset-y-0 left-0 rounded-sm bg-success/14"
                      :style="{ width: `${row.cumulativeWidth}%` }"
                    ></div>
                    <span class="relative z-10 text-success whitespace-nowrap">{{ priceText(row.price) }}</span>
                    <span class="relative z-10 text-right text-text-primary whitespace-nowrap">{{ quantityText(row.amount) }}</span>
                    <span class="relative z-10 text-right text-text-primary whitespace-nowrap">{{ currencyText(row.total) }}</span>
                  </div>
                </div>
              </div>
              <div data-testid="order-book-balance" class="border-t border-border/70 px-3 py-3">
                <div class="flex items-center gap-3 text-sm font-mono">
                  <span class="shrink-0 text-success">B {{ formatSpread(orderBookBidShare) }}</span>
                  <div class="relative h-1.5 flex-1 overflow-hidden rounded-full bg-border/60">
                    <div class="absolute inset-y-0 left-0 bg-success" :style="{ width: `${orderBookBidShare * 100}%` }"></div>
                    <div class="absolute inset-y-0 right-0 bg-danger" :style="{ width: `${orderBookAskShare * 100}%` }"></div>
                  </div>
                  <span class="shrink-0 text-danger">{{ formatSpread(orderBookAskShare) }} S</span>
                </div>
              </div>
            </div>
            <div v-else class="flex items-center justify-center h-full text-text-secondary text-sm">加载深度数据...</div>
          </template>
          <template v-else-if="viewMode === 'depth'">
            <template v-if="depthData">
              <div
                ref="depthChartContainer"
                data-testid="depth-chart-container"
                class="absolute inset-0 [&_a]:!hidden"
              ></div>
              <div
                v-if="hoveredDepthPoint"
                data-testid="depth-tooltip"
                class="absolute top-2 left-2 z-10 flex gap-3 text-xs font-mono pointer-events-none text-text-secondary"
