                </span>
                <span>价格 <span class="text-text-primary">{{ priceText(hoveredDepthPoint.price) }}</span></span>
                <span>累计 <span class="text-text-primary">{{ quantityText(hoveredDepthPoint.quantity) }}</span></span>
                <span>累计金额 <span class="text-text-primary">{{ currencyText(hoveredDepthPoint.amount) }}</span></span>
              </div>
            </template>
            <div v-else class="flex items-center justify-center h-full text-text-secondary text-sm">加载深度数据...</div>
          </template>
          <template v-else>
