              ref="priceChartContainer"
              class="absolute inset-0 [&_a]:!hidden"
              @touchstart.passive="onPriceChartInteractionStart"
              @touchend.passive="onPriceChartInteractionEnd"
              @touchcancel.passive="onPriceChartInteractionEnd"
            ></div>
            <div v-else class="flex items-center justify-center h-full text-text-secondary text-sm">暂无数据</div>
            <div v-if="hoveredCandle" class="absolute top-2 left-2 z-10 flex gap-3 text-xs font-mono pointer-events-none text-text-secondary">
              <span>{{ hoveredCandle.t }}</span>
              <span>O <span class="text-text-primary">{{ priceText(hoveredCandle.o) }}</span></span>
              <span>H <span class="text-text-primary">{{ priceText(hoveredCandle.h) }}</span></span>
              <span>L <span class="text-text-primary">{{ priceText(hoveredCandle.l) }}</span></span>
              <span>C <span class="text-text-primary">{{ priceText(hoveredCandle.c) }}</span></span>
              <span>V <span class="text-text-primary">{{ quantityText(hoveredCandle.v) }}</span></span>
            </div>
          </template>
        </div>
      </div>

      <!-- Market Stats + Recent Trades -->
      <div class="flex flex-wrap items-start gap-4 mb-4">
        <!-- Market Stats -->
        <div class="bg-bg-secondary border border-border rounded-lg px-4 py-3 flex-1 min-w-[280px]">
          <div class="flex flex-wrap gap-x-5 gap-y-2 text-sm">
            <div class="flex items-center gap-1.5">
              <span class="text-text-secondary">持仓人数</span>
              <span class="font-mono font-semibold text-text-primary">{{ quantityText(market.total_holders) }}</span>
            </div>
            <div class="flex items-center gap-1.5">
              <span class="text-text-secondary">总量</span>
              <span class="font-mono font-semibold text-text-primary">{{ quantityText(market.total_quantity) }}</span>
            </div>
            <div class="flex items-center gap-1.5">
              <span class="text-text-secondary">总价值</span>
              <span class="font-mono font-semibold text-text-primary">{{ currencyText(market.total_value) }}</span>
            </div>
            <div class="flex items-center gap-1.5">
              <span class="text-text-secondary">6h 买入</span>
              <span class="font-mono font-semibold text-text-primary">{{ currencyText(market.buy_volume) }}</span>
            </div>
            <div class="flex items-center gap-1.5">
              <span class="text-text-secondary">6h 卖出</span>
              <span class="font-mono font-semibold text-text-primary">{{ currencyText(market.sell_volume) }}</span>
            </div>
            <div class="flex items-center gap-1.5">
              <span class="text-text-secondary">净流入</span>
              <span class="font-mono font-semibold" :style="{ color: netFlow >= 0 ? 'var(--color-success)' : 'var(--color-danger)' }">
                {{ formatNetFlow(netFlow) }}
              </span>
            </div>
            <div class="flex items-center gap-1.5">
              <span class="text-text-secondary">{{ timeRange }}h 成交量</span>
              <span class="font-mono font-semibold text-text-primary">{{ quantityText(rangeVolume) }}</span>
            </div>
          </div>
          <!-- Latest K-line compact -->
          <div v-if="latestCandle" class="flex flex-wrap gap-x-5 gap-y-1 text-sm mt-2 pt-2 border-t border-border">
            <span class="text-text-secondary">最新K线</span>
            <span class="font-mono text-text-primary">O {{ priceText(latestCandle.open ?? latestCandle.close) }}</span>
            <span class="font-mono text-text-primary">H {{ priceText(latestCandle.high ?? latestCandle.close) }}</span>
            <span class="font-mono text-text-primary">L {{ priceText(latestCandle.low ?? latestCandle.close) }}</span>
            <span class="font-mono text-text-primary">C {{ priceText(latestCandle.close) }}</span>
            <span
              class="font-mono font-semibold"
              :style="{ color: (latestCandle.close - (latestCandle.open ?? latestCandle.close)) >= 0 ? 'var(--color-success)' : 'var(--color-danger)' }"
            >
              {{ formatSignedCurrency(latestCandle.close - (latestCandle.open ?? latestCandle.close)) }}
              ({{ formatSignedPercent((latestCandle.open ?? latestCandle.close) > 0 ? ((latestCandle.close - (latestCandle.open ?? latestCandle.close)) / (latestCandle.open ?? latestCandle.close)) : 0, { digits: 2 }) }})
            </span>
          </div>
          <!-- 24H OHLC -->
          <div v-if="stats24h" class="flex flex-wrap gap-x-5 gap-y-1 text-sm mt-2 pt-2 border-t border-border">
            <span class="text-text-secondary">24H</span>
            <span class="font-mono text-text-primary">O {{ priceText(stats24h.open) }}</span>
            <span class="font-mono text-text-primary">H {{ priceText(stats24h.high) }}</span>
            <span class="font-mono text-text-primary">L {{ priceText(stats24h.low) }}</span>
            <span class="font-mono text-text-primary">C {{ priceText(stats24h.close) }}</span>
            <span class="font-mono font-semibold" :style="{ color: stats24h.change >= 0 ? 'var(--color-success)' : 'var(--color-danger)' }">
              {{ formatSignedCurrency(stats24h.change) }} ({{ formatSignedPercent(stats24h.changePct, { digits: 2 }) }})
            </span>
          </div>
        </div>

        <!-- Recent Trades -->
        <div v-if="market.recent_trades?.length" class="bg-bg-secondary border border-border rounded-lg px-4 py-3 min-w-[280px] lg:w-[360px]">
