          <div class="max-h-[200px] overflow-y-auto">
            <table class="w-full text-xs">
              <thead class="sticky top-0 bg-bg-secondary">
                <tr class="text-text-secondary">
                  <th class="text-left py-1 pr-2 font-medium">时间</th>
                  <th class="text-left py-1 px-2 font-medium">方向</th>
                  <th class="text-right py-1 px-2 font-medium">数量</th>
                  <th class="text-right py-1 pl-2 font-medium">价格</th>
                </tr>
              </thead>
              <tbody>
                <tr
                  v-for="trade in market.recent_trades"
                  :key="recentTradeIdentity(trade)"
                  class="border-t border-border/50"
                  :class="recentTradeAnimationClass(trade)"
                >
                  <td class="py-1 pr-2 font-mono text-text-secondary whitespace-nowrap">{{ formatTradeTime(trade.ts) }}</td>
                  <td class="py-1 px-2 whitespace-nowrap">
                    <span
                      class="inline-block w-[30px] text-center text-[11px] font-medium rounded px-1 py-px"
                      :class="trade.side === 'buy' ? 'bg-success/15 text-success' : 'bg-danger/15 text-danger'"
                    >{{ trade.side === 'buy' ? '买' : '卖' }}</span>
                  </td>
                  <td class="py-1 px-2 font-mono text-text-primary text-right whitespace-nowrap">{{ compactQtyText(trade.qty) }}</td>
                  <td class="py-1 pl-2 font-mono text-text-primary text-right whitespace-nowrap">{{ priceText(trade.price) }}</td>
                </tr>
              </tbody>
            </table>
          </div>
        </div>
      </div>

      <!-- Tab Section -->
      <div class="mt-2 pt-4 border-t border-border">
