            class="px-4 py-2 rounded-md text-sm font-medium cursor-pointer transition-all duration-150"
            :class="activeTab === 'portfolio'
              ? 'bg-accent text-white'
              : 'bg-bg-secondary text-text-secondary border border-border hover:text-text-primary hover:border-text-secondary'"
            @click="switchTab('portfolio')"
            role="tab"
            :aria-selected="activeTab === 'portfolio'"
            aria-controls="panel-portfolio"
            id="tab-portfolio"
