            >{{ activeOrderCount }}</span>
          </button>
          <button
            class="px-4 py-2 rounded-md text-sm font-medium cursor-pointer transition-all duration-150"
            :class="activeTab === 'farm'
              ? 'bg-accent text-white'
              : 'bg-bg-secondary text-text-secondary border border-border hover:text-text-primary hover:border-text-secondary'"
            @click="switchTab('farm')"
            role="tab"
            :aria-selected="activeTab === 'farm'"
            aria-controls="panel-farm"
            id="tab-farm"
          >
            种植
          </button>
          <button
            class="px-4 py-2 rounded-md text-sm font-medium cursor-pointer transition-all duration-150"
            :class="activeTab === 'transactions'
              ? 'bg-accent text-white'
              : 'bg-bg-secondary text-text-secondary border border-border hover:text-text-primary hover:border-text-secondary'"
            @click="switchTab('transactions')"
            role="tab"
            :aria-selected="activeTab === 'transactions'"
            aria-controls="panel-transactions"
            id="tab-transactions"
          >
            交易记录
          </button>
        </div>

        <!-- ==================== Portfolio Tab ==================== -->
        <div v-if="activeTab === 'portfolio'" role="tabpanel" id="panel-portfolio" aria-labelledby="tab-portfolio">
