            <span class="sr-only">加载中...</span>
            <div class="grid grid-cols-1 gap-3 md:grid-cols-2">
              <div
                v-for="index in 2"
                :key="`portfolio-trade-panel-${index}`"
                class="space-y-3 rounded-lg border border-border bg-bg-secondary p-4"
              >
                <div class="h-4 w-28 rounded bg-bg-tertiary/70 animate-pulse"></div>
                <div class="h-10 rounded-md bg-bg-tertiary/60 animate-pulse"></div>
                <div class="h-4 w-40 rounded bg-bg-tertiary/60 animate-pulse"></div>
              </div>
            </div>
            <div class="grid grid-cols-2 gap-2 md:grid-cols-3 md:gap-3">
              <div
                v-for="index in 6"
                :key="`portfolio-card-${index}`"
                class="space-y-2 rounded-lg border border-border bg-bg-secondary px-4 py-4"
              >
                <div class="h-3 w-16 rounded bg-bg-tertiary/70 animate-pulse"></div>
                <div class="h-6 w-24 rounded bg-bg-tertiary/80 animate-pulse"></div>
              </div>
            </div>
          </div>

          <!-- Portfolio error -->
          <div v-else-if="portfolioError" class="flex items-center gap-3 py-3 px-4 text-danger text-sm bg-danger/10 rounded-md border border-danger/20">
