                    <span>保底收入 {{ priceText(insurancePnlBreakdown(seed, insuranceQuotes.get(seed.id)!).floorIncome) }}</span>
                  </div>
                  <div class="text-[11px] text-text-secondary mt-0.5">
                    保本卖出价 {{ priceText(insurancePnlBreakdown(seed, insuranceQuotes.get(seed.id)!).breakeven) }}/颗
                  </div>
                </div>

                <div v-else-if="!insuranceQuotes.get(seed.id)?.error" class="text-[13px] text-text-secondary mb-3">
                  拖动保底比例滑块查看报价
                </div>

                <button
                  class="w-full h-9 rounded-md text-sm font-medium bg-accent text-white hover:bg-accent/90 transition-colors disabled:opacity-50"
                  :disabled="insuranceBuying !== null || !insuranceQuotes.get(seed.id)?.success"
                  @click="buyInsurance(seed.id)"
                >
                  {{ insuranceBuying === seed.id ? '购买中...' : '确认购买' }}
                </button>
              </div>
            </div>

            <!-- Active policies display -->
            <div v-if="activePolicies.length > 0" class="mt-6">
              <h3 class="text-base font-semibold text-text-primary mb-3">🛡️ 已投保</h3>
              <div
                v-for="policy in activePolicies"
                :key="'policy-' + policy.id"
                class="bg-bg-secondary border border-border rounded-lg p-4 mb-2.5"
              >
                <div class="flex items-center justify-between mb-2">
                  <span class="text-sm font-medium text-text-primary">
                    保单 #{{ policy.id }} — {{ modeLabel(policy.mode) }}
                  </span>
                  <span class="text-[12px] text-text-secondary">种子 #{{ policy.seed_id }}</span>
                </div>
                <div class="text-[13px] text-text-secondary space-y-1 mb-2">
                  <div class="flex justify-between">
                    <span>保底价</span>
                    <span class="font-mono text-text-primary">{{ priceText(policy.strike) }} ({{ (policy.coverage_level * 100).toFixed(0) }}%)</span>
                  </div>
                  <div class="flex justify-between">
                    <span>覆盖量</span>
                    <span class="font-mono text-text-primary">{{ quantityText(policy.coverage_qty) }}颗</span>
                  </div>
                  <div class="flex justify-between">
                    <span>保费</span>
                    <span class="font-mono text-text-primary">{{ priceText(policy.premium_paid) }}</span>
                  </div>
                  <div class="flex justify-between items-center">
                    <span>到期</span>
                    <span class="font-mono text-text-primary text-[12px]">{{ insuranceExpiryRemaining(policy.expires_at) }}</span>
                  </div>
                </div>
                <!-- Expiry progress bar -->
                <div class="h-1.5 bg-bg-tertiary rounded-full overflow-hidden mb-3">
                  <div
                    class="h-full bg-accent rounded-full transition-all duration-300"
                    :style="{ width: insuranceExpiryPercent(policy) + '%' }"
                  ></div>
                </div>
                <!-- Cancel section for American -->
                <div v-if="policy.mode === 'american'" class="space-y-2">
                  <div v-if="cancelRefundQuotes.get(policy.id)" class="flex justify-between text-[12px]">
                    <span class="text-text-secondary">预计退款</span>
                    <span class="font-mono text-warning">≈ {{ priceText(cancelRefundQuotes.get(policy.id)!) }}</span>
                  </div>
                  <button
                    class="w-full h-8 rounded-md text-[13px] font-medium border border-border text-text-secondary hover:text-danger hover:border-danger transition-colors disabled:opacity-50"
                    :disabled="insuranceCancelling !== null"
                    @click="cancelInsurance(policy.id)"
                  >
                    {{ insuranceCancelling === policy.id ? '退保中...' : '退保' }}
                  </button>
                </div>
              </div>
            </div>

            <!-- Policy history (collapsible) -->
            <div v-if="settledPolicies.length > 0" class="mt-6">
              <button
                class="flex items-center gap-2 text-sm font-semibold text-text-secondary hover:text-text-primary transition-colors"
                @click="insuranceHistoryExpanded = !insuranceHistoryExpanded"
              >
                📋 保单历史 ({{ settledPolicies.length }})
                <span class="text-[12px]">{{ insuranceHistoryExpanded ? '▲' : '▼' }}</span>
              </button>
              <div v-if="insuranceHistoryExpanded" class="mt-2 space-y-1.5">
                <div
                  v-for="policy in settledPolicies"
                  :key="'hist-' + policy.id"
                  class="flex items-center justify-between px-3 py-2 bg-bg-secondary border border-border rounded text-[13px]"
                >
                  <div class="flex items-center gap-2">
                    <span>{{ policy.status === 'settled' ? '📋' : '❌' }}</span>
                    <span class="font-mono text-text-secondary">#{{ policy.id }}</span>
                    <span class="text-text-secondary">{{ modeLabel(policy.mode) }}</span>
                    <span class="text-text-secondary">种子#{{ policy.seed_id }}</span>
                  </div>
                  <div class="font-mono">
                    <span v-if="policy.status === 'settled' && policy.payout != null && policy.payout > 0" class="text-success">
                      赔付 {{ priceText(policy.payout) }}
                    </span>
                    <span v-else-if="policy.status === 'settled'" class="text-text-secondary">
                      未触发保底
                    </span>
                    <span v-else-if="policy.status === 'cancelled'" class="text-warning">
                      退款 {{ priceText(policy.cancel_refund ?? 0) }}
                    </span>
                  </div>
                </div>
              </div>
            </div>

            <!-- Treasury health bar -->
            <div v-if="insuranceTreasury" class="mt-6 p-3 bg-bg-secondary border border-border rounded-lg">
              <div class="flex items-center justify-between text-[13px] mb-2">
                <span class="text-text-secondary">🏦 保险金库</span>
                <span class="text-text-secondary">{{ treasuryStatusText(insuranceTreasury) }}</span>
              </div>
              <div class="flex items-center gap-3">
                <div class="flex-1 h-2 bg-bg-tertiary rounded-full overflow-hidden">
                  <div
                    :class="['h-full rounded-full transition-all duration-300', treasuryUtilColor(insuranceTreasury.utilization)]"
                    :style="{ width: Math.min(100, insuranceTreasury.utilization * 100) + '%' }"
                  ></div>
                </div>
                <span class="text-[12px] font-mono text-text-secondary min-w-[4ch]">{{ (insuranceTreasury.utilization * 100).toFixed(1) }}%</span>
              </div>
              <div class="flex justify-between text-[11px] text-text-secondary mt-1">
                <span>余额 {{ priceText(insuranceTreasury.balance) }}</span>
                <span>{{ insuranceTreasury.policy_count }} 份活跃保单</span>
              </div>
            </div>

          </template>
        </div>

        <!-- ==================== Transactions Tab ==================== -->
        <div v-if="activeTab === 'transactions'" role="tabpanel" id="panel-transactions" aria-labelledby="tab-transactions">
          <!-- Not authenticated -->
          <div v-if="!isAuthenticated" class="text-center py-8">
            <router-link to="/login" class="text-sm text-accent no-underline hover:underline">登录后可查看交易记录</router-link>
          </div>

          <!-- Transactions loading -->
          <div
            v-if="isAuthenticated && transactionsLoading"
            data-testid="turnip-transactions-skeleton"
            class="space-y-3"
            role="status"
            aria-live="polite"
            aria-busy="true"
          >
            <span class="sr-only">加载中...</span>
            <div class="flex flex-col gap-3 sm:flex-row">
              <div class="h-10 flex-1 rounded-md bg-bg-tertiary/60 animate-pulse"></div>
              <div class="h-10 w-full rounded-md bg-bg-tertiary/60 animate-pulse sm:w-36"></div>
              <div class="h-10 w-full rounded-md bg-bg-tertiary/60 animate-pulse sm:w-24"></div>
            </div>
            <div
              v-for="index in 4"
              :key="`transaction-skeleton-${index}`"
              class="h-16 rounded-lg border border-border bg-bg-secondary animate-pulse"
            ></div>
          </div>

          <!-- Transactions error -->
          <div v-if="isAuthenticated && transactionsError" class="text-center py-8 text-danger text-sm">
            {{ transactionsError }}
          </div>

          <!-- Filter and Search -->
          <div v-if="isAuthenticated && !transactionsLoading" class="mb-4 flex flex-col sm:flex-row gap-3">
            <div class="flex-1">
              <input
                v-model="transactionSearchTerm"
                type="text"
                aria-label="搜索交易记录"
                placeholder="搜索说明..."
                :class="primaryInputClass"
                @keyup.enter="applyTransactionFilters"
              />
            </div>
            <div class="flex gap-2">
              <select
                v-model="transactionTypeFilter"
                aria-label="筛选交易类型"
                :class="selectInputClass"
              >
                <option value="">全部类型</option>
                <option value="harvest">收获</option>
                <option value="buy">买入</option>
                <option value="sell">卖出</option>
                <option value="expire">过期</option>
                <option value="gift_in">收礼</option>
                <option value="gift_out">送礼</option>
                <option value="consume">消耗</option>
              </select>
              <button
                class="px-4 h-10 rounded-md text-sm font-medium bg-accent text-white hover:bg-accent/90 transition-colors"
                @click="applyTransactionFilters"
              >
                搜索
              </button>
            </div>
          </div>

          <!-- Transactions content -->
          <template v-if="isAuthenticated && !transactionsLoading && !transactionsError">
            <div v-if="transactions.length === 0" class="text-center py-8 text-text-secondary text-sm">
              暂无交易记录
            </div>

            <div v-else>
              <!-- Desktop table -->
              <div class="hidden md:block">
                <div class="overflow-x-auto border border-border rounded-lg bg-bg-secondary">
                  <table class="w-full border-collapse text-sm">
                    <thead class="bg-bg-tertiary">
                      <tr>
                        <th class="px-4 py-2.5 text-left font-medium text-[13px] text-text-secondary border-b border-border whitespace-nowrap">时间</th>
                        <th class="px-4 py-2.5 text-left font-medium text-[13px] text-text-secondary border-b border-border whitespace-nowrap">类型</th>
                        <th class="px-4 py-2.5 text-right font-medium text-[13px] text-text-secondary border-b border-border whitespace-nowrap">数量</th>
                        <th class="px-4 py-2.5 text-right font-medium text-[13px] text-text-secondary border-b border-border whitespace-nowrap">单价</th>
                        <th class="px-4 py-2.5 text-right font-medium text-[13px] text-text-secondary border-b border-border whitespace-nowrap">余额</th>
                        <th class="px-4 py-2.5 text-left font-medium text-[13px] text-text-secondary border-b border-border">说明</th>
                      </tr>
                    </thead>
                    <tbody>
                      <tr
                        v-for="tx in transactions"
                        :key="tx.id"
                        class="border-b border-border last:border-b-0 hover:bg-bg-tertiary transition-colors"
                      >
                        <td class="px-4 py-3 text-text-secondary whitespace-nowrap text-[13px]">
                          {{ formatDateTime(tx.created_at) }}
                        </td>
                        <td class="px-4 py-3 whitespace-nowrap text-[13px]">
                          <span
                            class="px-2 py-0.5 rounded text-xs font-medium"
                            :class="{
                              'bg-success/10 text-success': tx.tx_type === 'buy' || tx.tx_type === 'harvest' || tx.tx_type === 'gift_in',
                              'bg-accent/10 text-accent': tx.tx_type === 'sell',
                              'bg-danger/10 text-danger': tx.tx_type === 'expire' || tx.tx_type === 'consume',
                              'bg-text-secondary/10 text-text-secondary': tx.tx_type === 'gift_out',
                            }"
                          >
                            {{ getTxTypeLabel(tx.tx_type) }}
                          </span>
                        </td>
                        <td class="px-4 py-3 text-right whitespace-nowrap font-mono text-[13px]"
                            :class="quantityNumber(tx.quantity) >= 0 ? 'text-success' : 'text-danger'">
                          {{ quantityNumber(tx.quantity) >= 0 ? '+' : '' }}{{ quantityText(tx.quantity) }}
                        </td>
                        <td class="px-4 py-3 text-right whitespace-nowrap font-mono text-text-primary text-[13px]">
                          {{ priceText(tx.unit_price) }}
                          <span
                            v-if="tx.mid_price && transactionMidDeltaText(tx)"
                            class="ml-1 text-[11px]"
                            :class="transactionMidDeltaClass(tx)"
                          >{{ transactionMidDeltaText(tx) }}</span>
                        </td>
                        <td class="px-4 py-3 text-right whitespace-nowrap font-mono text-text-primary text-[13px]">
                          {{ quantityText(tx.balance_after) }}
                        </td>
                        <td class="px-4 py-3 text-text-secondary text-[13px] truncate max-w-[200px]" :title="tx.description">
                          {{ tx.description }}
                        </td>
                      </tr>
                    </tbody>
                  </table>
                </div>
              </div>

              <!-- Mobile cards -->
              <div class="block md:hidden space-y-3">
                <div
                  v-for="tx in transactions"
                  :key="tx.id"
                  class="bg-bg-secondary border border-border rounded-lg p-4"
                >
                  <div class="flex items-start justify-between mb-3">
                    <span
                      class="px-2 py-0.5 rounded text-xs font-medium"
                      :class="{
                        'bg-success/10 text-success': tx.tx_type === 'buy' || tx.tx_type === 'harvest' || tx.tx_type === 'gift_in',
                        'bg-accent/10 text-accent': tx.tx_type === 'sell',
                        'bg-danger/10 text-danger': tx.tx_type === 'expire' || tx.tx_type === 'consume',
                        'bg-text-secondary/10 text-text-secondary': tx.tx_type === 'gift_out',
                      }"
                    >
                      {{ getTxTypeLabel(tx.tx_type) }}
                    </span>
                    <span class="text-xs text-text-secondary">{{ formatDateTime(tx.created_at) }}</span>
                  </div>
                  <div class="space-y-2">
                    <div class="flex items-center justify-between text-sm">
                      <span class="text-text-secondary">数量</span>
                      <span class="font-mono font-semibold"
                            :class="quantityNumber(tx.quantity) >= 0 ? 'text-success' : 'text-danger'">
                        {{ quantityNumber(tx.quantity) >= 0 ? '+' : '' }}{{ quantityText(tx.quantity) }}
                      </span>
                    </div>
                    <div class="flex items-center justify-between text-sm">
                      <span class="text-text-secondary">单价</span>
                      <span class="font-mono font-semibold text-text-primary">
                        {{ priceText(tx.unit_price) }}
                        <span
                          v-if="tx.mid_price && transactionMidDeltaText(tx)"
                          class="ml-1 text-[11px]"
                          :class="transactionMidDeltaClass(tx)"
                        >{{ transactionMidDeltaText(tx) }}</span>
                      </span>
                    </div>
                    <div class="flex items-center justify-between text-sm">
                      <span class="text-text-secondary">余额</span>
                      <span class="font-mono font-semibold text-text-primary">{{ quantityText(tx.balance_after) }}</span>
                    </div>
                    <div class="text-sm text-text-secondary pt-2 border-t border-border">
                      {{ tx.description }}
                    </div>
                  </div>
                </div>
              </div>

              <!-- Load More Button -->
              <div v-if="transactionsHasMore" class="mt-4 text-center">
                <button
                  class="px-6 py-2 rounded-md text-sm font-medium bg-bg-secondary text-text-primary border border-border hover:border-accent hover:text-accent transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                  :disabled="transactionsLoadingMore"
                  @click="loadMoreTransactions"
                >
                  {{ transactionsLoadingMore ? '加载中...' : '加载更多' }}
                </button>
              </div>
            </div>
          </template>
        </div>
      </div>
    </template>
  </div>
</template>
